// Bilingual question bank for "The Drop".
// Each question offers four real-world statistics; exactly one is the true
// figure. Distractors are plausible near-values. Classifier-authored metadata
// in difficulty/ assigns every id to the easy, medium, or hard round pool.

import { getDropQuestionDifficulty, type DropDifficulty } from './difficulty';
import type { DropQuestion } from './logic';

export type Language = 'en' | 'pl';

/** A single-locale Drop card, as stored in a premium pack's `content.en`/`.pl`. */
export interface DropPackCard {
    id: string;
    prompt: string;
    options: string[];
    correctIndex: number;
    difficulty: DropDifficulty;
}

/**
 * Combine the English and Polish single-locale cards of an owned pack (same
 * index) into the bilingual {@link DropQuestion} the game plays. Lets owned
 * packs merge into the bilingual pool without touching the render path.
 */
export function zipDropCard(en: DropPackCard, pl: DropPackCard): DropQuestion {
    if (
        en.id !== pl.id ||
        en.correctIndex !== pl.correctIndex ||
        en.difficulty !== pl.difficulty ||
        en.options.length !== pl.options.length
    ) {
        throw new Error(`Mismatched EN/PL The Drop cards: "${en.id}" / "${pl.id}".`);
    }
    return {
        id: en.id,
        prompt: { en: en.prompt, pl: pl.prompt },
        options: en.options.map((opt, i) => ({ en: opt, pl: pl.options[i] })),
        correctIndex: en.correctIndex,
        difficulty: en.difficulty,
    };
}

